interface.signature:
public interface IMigrationService
{
    Task RunStartupAsync();
    Task ApplyMigrationsAsync();
    Task<bool> CheckDatabaseIntegrityAsync();
    Task CreateBackupAsync(string backupReason);
}

var pending = (await _context.Database.GetPendingMigrationsAsync()).ToList();
if (!pending.Any()) { _logger.LogInformation("No pending migrations."); return; }
await CreateBackupAsync("pre-migration");
await _context.Database.MigrateAsync();
var latest = (await _context.Database.GetAppliedMigrationsAsync()).Last();
// upsert system_state where state_name = 'DatabaseSchemaVersion'

using var conn = _context.Database.GetDbConnection();
await _context.Database.OpenConnectionAsync();
using var cmd = conn.CreateCommand();
cmd.CommandText = "PRAGMA integrity_check;";
var result = await cmd.ExecuteScalarAsync();
return result?.ToString() == "ok";

var backupPath = Path.Combine(AppDataDir, $"calendar_backup_{DateTime.UtcNow:yyyyMMdd_HHmmss}_{backupReason}.db");
File.Copy(Path.Combine(AppDataDir, "calendar.db"), backupPath, overwrite: false);
Directory.GetFiles(AppDataDir, "calendar_backup_*.db")
    .OrderByDescending(File.GetCreationTimeUtc).Skip(5)
    .ToList().ForEach(File.Delete);

using var scope = _serviceProvider.CreateScope();
var migrationService = scope.ServiceProvider.GetRequiredService<IMigrationService>();
try { await migrationService.RunStartupAsync(); }
catch (Exception ex) { /* show ContentDialog, Application.Current.Exit() */ }
